1	// Command govirt provisions VMs locally (libvirt/KVM) or in the cloud (AWS EC2,
2	// DigitalOcean) from a single JSON config and a standard cloud-init YAML.
3	package main
4	
5	import (
6		"context"
7		"fmt"
8		"os"
9		"path/filepath"
10		"text/tabwriter"
11	
12		"github.com/gherlein/govirt/internal/cloudinit"
13		"github.com/gherlein/govirt/internal/config"
14		"github.com/gherlein/govirt/internal/images"
15		"github.com/gherlein/govirt/internal/provider"
16		"github.com/gherlein/govirt/internal/provider/aws"
17		"github.com/gherlein/govirt/internal/provider/digitalocean"
18		"github.com/gherlein/govirt/internal/provider/libvirt"
19	)
20	
21	// version is set via -ldflags at build time.
22	var version = "dev"
23	
24	func main() {
25		if err := run(os.Args[1:]); err != nil {
26			fmt.Fprintln(os.Stderr, "error:", err)
27			os.Exit(1)
28		}
29	}
30	
31	func run(argv []string) error {
32		args, err := parseArgs(argv)
33		if err != nil {
34			return err
35		}
36		if args.version {
37			fmt.Println("govirt", version)
38			return nil
39		}
40		if args.help || args.command == "" {
41			printUsage()
42			return nil
43		}
44	
45		ctx := context.Background()
46		folder := resolveStackFolder(args.folder, args.dir, os.Getenv("GOVIRT_STACK_FOLDER"), homeDir())
47	
48		switch args.command {
49		case "create":
50			return cmdCreate(ctx, args, folder)
51		case "destroy":
52			return cmdDestroy(ctx, args, folder)
53		case "list":
54			return cmdList(ctx, args)
55		case "ssh":
56			return cmdSimple(ctx, args, folder, "ssh")
57		case "status":
58			return cmdStatus(ctx, args, folder)
59		case "stop":
60			return cmdSimple(ctx, args, folder, "stop")
61		case "start":
62			return cmdSimple(ctx, args, folder, "start")
63		case "dns":
64			return cmdDNS(ctx, args, folder)
65		default:
66			return fmt.Errorf("unknown command %q (try 'govirt --help')", args.command)
67		}
68	}
69	
70	// buildProvider constructs the concrete provider for a name.
71	func buildProvider(name string, verbose bool) (provider.VMProvider, error) {
72		switch name {
73		case "local":
74			p := libvirt.New(images.NewManager())
75			p.Verbose = verbose
76			return p, nil
77		case "aws":
78			return aws.New(), nil
79		case "do":
80			return digitalocean.New(), nil
81		default:
82			return nil, fmt.Errorf("unknown provider %q", name)
83		}
84	}
85	
86	// loadStackConfig loads and validates a stack config, applying a --users
87	// override when present.
88	func loadStackConfig(args parsedArgs, folder string) (*config.Config, string, error) {
89		if args.name == "" {
90			return nil, "", fmt.Errorf("%s requires a VM name", args.command)
91		}
92		cfgPath := config.ConfigPath(folder, args.name)
93		cfg, err := config.Load(cfgPath)
94		if err != nil {
95			return nil, "", err
96		}
97		if args.users != "" && cfg.VM != nil {
98			cfg.VM.Users = parseUsersOverride(args.users)
99		}
100		return cfg, cfgPath, nil
101	}
102	
103	func cmdCreate(ctx context.Context, args parsedArgs, folder string) error {
104		cfg, cfgPath, err := loadStackConfig(args, folder)
105		if err != nil {
106			return err
107		}
108		if err := cfg.Validate(); err != nil {
109			return err
110		}
111		providerName := selectProvider(args.provider, cfg)
112		p, err := buildProvider(providerName, args.verbose)
113		if err != nil {
114			return err
115		}
116	
117		processed, err := processCloudInit(ctx, cfg, folder, args.name, providerName == "local")
118		if err != nil {
119			return err
120		}
121		tmp, err := os.CreateTemp("", "govirt-cloudinit-*.yaml")
122		if err != nil {
123			return err
124		}
125		defer os.Remove(tmp.Name())
126		if _, err := tmp.Write(processed); err != nil {
127			tmp.Close()
128			return err
129		}
130		tmp.Close()
131	
132		if err := p.Create(ctx, cfg, tmp.Name()); err != nil {
133			return err
134		}
135	
136		if providerName == "local" && !args.noHosts {
137			updateLocalHosts(cfg)
138		}
139		if err := config.Save(cfgPath, cfg); err != nil {
140			return err
141		}
142		fmt.Printf("created %s (%s)\n", args.name, providerName)
143		return nil
144	}
145	
146	// processCloudInit reads the stack cloud-init.yaml (or generates a default) and
147	// runs it through the processor.
148	func processCloudInit(ctx context.Context, cfg *config.Config, folder, name string, local bool) ([]byte, error) {
149		ciPath := config.CloudInitPath(folder, name)
150		var raw []byte
151		if data, err := os.ReadFile(ciPath); err == nil {
152			raw = data
153		} else if os.IsNotExist(err) {
154			raw = []byte(defaultCloudInit(cfg))
155		} else {
156			return nil, fmt.Errorf("reading %s: %w", ciPath, err)
157		}
158		return cloudinit.Process(ctx, cfg, raw, cloudinit.NewKeyFetcher(), local)
159	}
160	
161	// updateLocalHosts adds an /etc/hosts entry for a freshly created local VM. A
162	// failure prints manual instructions and is non-fatal.
163	func updateLocalHosts(cfg *config.Config) {
164		if cfg.Local == nil || cfg.Local.IP == "" {
165			return
166		}
167		fqdn := ""
168		if cfg.DNS != nil && cfg.DNS.Hostname != "" && cfg.DNS.Domain != "" {
169			fqdn = cfg.DNS.Hostname + "." + cfg.DNS.Domain
170		}
171		if err := addHostsEntry(cfg.VM.Name, cfg.Local.IP, fqdn); err != nil {
172			fmt.Fprintf(os.Stderr, "warning: could not update /etc/hosts: %v\n", err)
173			fmt.Fprintf(os.Stderr, "add manually:\n%s\n", hostsBlock(cfg.VM.Name, cfg.Local.IP, fqdn))
174			return
175		}
176		cfg.Local.HostsEntry = true
177	}
178	
179	func cmdDestroy(ctx context.Context, args parsedArgs, folder string) error {
180		cfg, cfgPath, err := loadStackConfig(args, folder)
181		if err != nil {
182			return err
183		}
184		providerName := selectProvider(args.provider, cfg)
185		p, err := buildProvider(providerName, args.verbose)
186		if err != nil {
187			return err
188		}
189		hadHostsEntry := providerName == "local" && cfg.Local != nil && cfg.Local.HostsEntry
190		if err := p.Delete(ctx, cfg); err != nil {
191			return err
192		}
193		if hadHostsEntry {
194			if err := removeHostsEntry(args.name); err != nil {
195				fmt.Fprintf(os.Stderr, "warning: could not remove /etc/hosts entry: %v\n", err)
196			}
197		}
198		if err := config.Save(cfgPath, cfg); err != nil {
199			return err
200		}
201		fmt.Printf("destroyed %s (%s)\n", args.name, providerName)
202		return nil
203	}
204	
