1	package cloudinit
2	
3	import (
4		"context"
5		"fmt"
6		"strings"
7	
8		"github.com/gherlein/govirt/internal/config"
9		"gopkg.in/yaml.v3"
10	)
11	
12	// KeyProvider fetches SSH public keys for a GitHub user. *KeyFetcher satisfies it.
13	type KeyProvider interface {
14		Fetch(ctx context.Context, githubUser string) (string, error)
15	}
16	
17	// Process produces the final cloud-init document for a VM:
18	//
19	//  1. SSH public key placeholders are substituted from GitHub.
20	//  2. Go template syntax (when present) is rendered against the config.
21	//  3. For local VMs with mounts, runcmd/write_files entries are injected so the
22	//     host directories are mounted in the guest.
23	//
24	// injectMounts is true only for the local provider (virtiofs mounts are
25	// meaningless on cloud providers).
26	func Process(ctx context.Context, cfg *config.Config, raw []byte, keys KeyProvider, injectMounts bool) ([]byte, error) {
27		if cfg.VM == nil || len(cfg.VM.Users) == 0 {
28			return nil, fmt.Errorf("cloud-init processing requires at least one vm user")
29		}
30	
31		keysByUser, err := fetchAllKeys(ctx, cfg.VM.Users, keys)
32		if err != nil {
33			return nil, err
34		}
35	
36		out := substituteKeys(raw, cfg.VM.Users, keysByUser)
37	
38		out, err = renderTemplate(out, cfg)
39		if err != nil {
40			return nil, err
41		}
42	
43		if injectMounts && len(cfg.VM.Mounts) > 0 {
44			out, err = injectMountConfig(out, cfg.VM.Mounts)
45			if err != nil {
46				return nil, err
47			}
48		}
49		return out, nil
50	}
51	
52	func fetchAllKeys(ctx context.Context, users []config.User, keys KeyProvider) (map[string]string, error) {
53		byUser := make(map[string]string, len(users))
54		for _, u := range users {
55			k, err := keys.Fetch(ctx, u.GitHubUsername)
56			if err != nil {
57				return nil, err
58			}
59			byUser[u.Username] = k
60		}
61		return byUser, nil
62	}
63	
64	// substituteKeys replaces ${SSH_PUBLIC_KEY} (first user) and
65	// ${SSH_PUBLIC_KEY_<USERNAME>} placeholders. Multi-line key values are expanded
66	// preserving the indentation/prefix of the placeholder line so that YAML list
67	// items remain valid.
68	func substituteKeys(raw []byte, users []config.User, keysByUser map[string]string) []byte {
69		replacements := make(map[string]string, len(users)+1)
70		if len(users) > 0 {
71			replacements["${SSH_PUBLIC_KEY}"] = keysByUser[users[0].Username]
72		}
73		for _, u := range users {
74			token := "${SSH_PUBLIC_KEY_" + strings.ToUpper(u.Username) + "}"
75			replacements[token] = keysByUser[u.Username]
76		}
77	
78		lines := strings.Split(string(raw), "\n")
79		var result []string
80		for _, line := range lines {
81			token, idx := firstPlaceholder(line, replacements)
82			if idx < 0 {
83				result = append(result, line)
84				continue
85			}
86			prefix := line[:idx]
87			suffix := line[idx+len(token):]
88			value := replacements[token]
89			keyLines := strings.Split(strings.TrimRight(value, "\n"), "\n")
90			for i, kl := range keyLines {
91				if i == 0 {
92					result = append(result, prefix+kl+suffix)
93				} else {
94					result = append(result, prefix+kl)
95				}
96			}
97		}
98		return []byte(strings.Join(result, "\n"))
99	}
100	
101	// firstPlaceholder returns the earliest-occurring placeholder token on the line
102	// and its byte index, or ("", -1) if none are present.
103	func firstPlaceholder(line string, replacements map[string]string) (string, int) {
104		bestToken := ""
105		bestIdx := -1
106		for token := range replacements {
107			if i := strings.Index(line, token); i >= 0 {
108				if bestIdx < 0 || i < bestIdx {
109					bestIdx = i
110					bestToken = token
111				}
112			}
113		}
114		return bestToken, bestIdx
115	}
116	
117	// MountTag derives a virtiofs mount tag from a target path: slashes become
118	// hyphens and any leading hyphen is stripped. The same tag is used both for the
119	// virt-install --filesystem target and the in-guest mount command so they match.
120	func MountTag(target string) string {
121		tag := strings.ReplaceAll(target, "/", "-")
122		return strings.TrimPrefix(tag, "-")
123	}
124	
125	// injectMountConfig merges runcmd and write_files entries for each mount into
126	// the cloud-init document. The "#cloud-config" header is preserved; existing
127	// runcmd/write_files lists are appended to rather than replaced.
128	func injectMountConfig(raw []byte, mounts []config.Mount) ([]byte, error) {
129		header, body := splitCloudConfigHeader(raw)
130	
131		var doc map[string]any
132		if strings.TrimSpace(string(body)) == "" {
133			doc = map[string]any{}
134		} else if err := yaml.Unmarshal(body, &doc); err != nil {
135			return nil, fmt.Errorf("parsing cloud-init for mount injection: %w", err)
136		}
137		if doc == nil {
138			doc = map[string]any{}
139		}
140	
141		runcmd := toList(doc["runcmd"])
142		writeFiles := toList(doc["write_files"])
143		for _, m := range mounts {
144			tag := MountTag(m.Target)
145			runcmd = append(runcmd,
146				fmt.Sprintf("mkdir -p %s", m.Target),
147				fmt.Sprintf("mount -t virtiofs %s %s", tag, m.Target),
148			)
149			writeFiles = append(writeFiles, map[string]any{
150				"path":    "/etc/fstab",
151				"append":  true,
152				"content": fmt.Sprintf("%s   %s   virtiofs   defaults   0   0\n", tag, m.Target),
153			})
154		}
155		doc["runcmd"] = runcmd
156		doc["write_files"] = writeFiles
157	
158		merged, err := yaml.Marshal(doc)
159		if err != nil {
160			return nil, fmt.Errorf("encoding cloud-init after mount injection: %w", err)
161		}
162		return append([]byte(header), merged...), nil
163	}
164	
165	// splitCloudConfigHeader separates a leading "#cloud-config" comment line (with
166	// its trailing newline) from the rest of the document so it survives a
167	// marshal/unmarshal round trip.
168	func splitCloudConfigHeader(raw []byte) (header string, body []byte) {
169		s := string(raw)
170		if !strings.HasPrefix(s, "#cloud-config") {
171			return "", raw
172		}
173		if nl := strings.IndexByte(s, '\n'); nl >= 0 {
174			return s[:nl+1], []byte(s[nl+1:])
175		}
176		return s + "\n", nil
177	}
178	
179	func toList(v any) []any {
180		if v == nil {
181			return nil
182		}
183		if list, ok := v.([]any); ok {
184			return list
185		}
186		return []any{v}
187	}
