1	package cloudinit
2	
3	import (
4		"context"
5		"fmt"
6		"io"
7		"net/http"
8		"strings"
9		"time"
10	)
11	
12	// defaultGitHubBaseURL is the host SSH public keys are fetched from.
13	const defaultGitHubBaseURL = "https://github.com"
14	
15	// KeyFetcher retrieves SSH public keys for GitHub users.
16	//
17	// BaseURL and Client are exposed so tests can point at an httptest server. The
18	// production zero value (via NewKeyFetcher) talks to github.com with TLS
19	// verification enabled and a bounded timeout.
20	type KeyFetcher struct {
21		Client  *http.Client
22		BaseURL string
23	}
24	
25	// NewKeyFetcher returns a fetcher with secure defaults.
26	func NewKeyFetcher() *KeyFetcher {
27		return &KeyFetcher{
28			Client:  &http.Client{Timeout: 15 * time.Second},
29			BaseURL: defaultGitHubBaseURL,
30		}
31	}
32	
33	// Fetch returns the SSH public keys published at <base>/<githubUser>.keys.
34	// An empty key set is treated as an error.
35	func (f *KeyFetcher) Fetch(ctx context.Context, githubUser string) (string, error) {
36		url := fmt.Sprintf("%s/%s.keys", strings.TrimRight(f.BaseURL, "/"), githubUser)
37		req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
38		if err != nil {
39			return "", fmt.Errorf("building key request for %s: %w", githubUser, err)
40		}
41		resp, err := f.Client.Do(req)
42		if err != nil {
43			return "", fmt.Errorf("fetching keys for %s: %w", githubUser, err)
44		}
45		defer resp.Body.Close()
46		if resp.StatusCode != http.StatusOK {
47			return "", fmt.Errorf("no SSH keys found for %s: verify GitHub username at github.com/%s.keys", githubUser, githubUser)
48		}
49		body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
50		if err != nil {
51			return "", fmt.Errorf("reading keys for %s: %w", githubUser, err)
52		}
53		keys := strings.TrimSpace(string(body))
54		if keys == "" {
55			return "", fmt.Errorf("no SSH keys found for %s: verify GitHub username at github.com/%s.keys", githubUser, githubUser)
56		}
57		return keys, nil
58	}
