1	package cloudinit
2	
3	import (
4		"bytes"
5		"fmt"
6		"text/template"
7	)
8	
9	// hasGoTemplate reports whether the document uses Go template syntax.
10	func hasGoTemplate(data []byte) bool {
11		return bytes.Contains(data, []byte("{{"))
12	}
13	
14	// renderTemplate runs the document through text/template with data only when it
15	// contains Go template markers. Documents without "{{" are returned unchanged.
16	func renderTemplate(data []byte, tmplData any) ([]byte, error) {
17		if !hasGoTemplate(data) {
18			return data, nil
19		}
20		tmpl, err := template.New("cloud-init").Option("missingkey=error").Parse(string(data))
21		if err != nil {
22			return nil, fmt.Errorf("parsing cloud-init template: %w", err)
23		}
24		var buf bytes.Buffer
25		if err := tmpl.Execute(&buf, tmplData); err != nil {
26			return nil, fmt.Errorf("rendering cloud-init template: %w", err)
27		}
28		return buf.Bytes(), nil
29	}
