1	// Package images downloads and caches Ubuntu cloud images used by the local
2	// libvirt provider. Cached images are never deleted automatically.
3	package images
4	
5	import (
6		"context"
7		"crypto/sha256"
8		"encoding/hex"
9		"fmt"
10		"io"
11		"net/http"
12		"os"
13		"path/filepath"
14		"strings"
15		"time"
16	)
17	
18	// DefaultBaseURL is the Ubuntu cloud image host.
19	const DefaultBaseURL = "https://cloud-images.ubuntu.com"
20	
21	// release maps an image shorthand to its codename and image file name.
22	type release struct {
23		codename string
24		file     string
25	}
26	
27	var releases = map[string]release{
28		"24.04": {"noble", "noble-server-cloudimg-amd64.img"},
29		"22.04": {"jammy", "jammy-server-cloudimg-amd64.img"},
30		"20.04": {"focal", "focal-server-cloudimg-amd64.img"},
31	}
32	
33	// ResolveURL returns the canonical download URL for an image shorthand using the
34	// default Ubuntu host.
35	func ResolveURL(image string) (string, error) {
36		url, _, _, err := resolve(DefaultBaseURL, image)
37		return url, err
38	}
39	
40	func resolve(base, image string) (imageURL, checksumURL, filename string, err error) {
41		r, ok := releases[image]
42		if !ok {
43			return "", "", "", fmt.Errorf("unknown image shorthand %q: supported values are 24.04, 22.04, 20.04", image)
44		}
45		prefix := fmt.Sprintf("%s/%s/current", strings.TrimRight(base, "/"), r.codename)
46		return prefix + "/" + r.file, prefix + "/SHA256SUMS", r.file, nil
47	}
48	
49	// Manager downloads and caches cloud images.
50	type Manager struct {
51		CacheDir string
52		Client   *http.Client
53		BaseURL  string
54		// Progress receives human-readable download progress. Defaults to os.Stderr.
55		Progress io.Writer
56	}
57	
58	// DefaultCacheDir returns $GOVIRT_IMAGE_CACHE or ~/.cache/govirt/images.
59	func DefaultCacheDir() string {
60		if v := os.Getenv("GOVIRT_IMAGE_CACHE"); v != "" {
61			return v
62		}
63		home, err := os.UserHomeDir()
64		if err != nil {
65			return filepath.Join(os.TempDir(), "govirt", "images")
66		}
67		return filepath.Join(home, ".cache", "govirt", "images")
68	}
69	
70	// NewManager returns a Manager with secure defaults.
71	func NewManager() *Manager {
72		return &Manager{
73			CacheDir: DefaultCacheDir(),
74			Client:   &http.Client{Timeout: 30 * time.Minute},
75			BaseURL:  DefaultBaseURL,
76			Progress: os.Stderr,
77		}
78	}
79	
80	// Ensure returns the local path to the cached image for the given shorthand,
81	// downloading and verifying it on a cache miss.
82	func (m *Manager) Ensure(ctx context.Context, image string) (string, error) {
83		imageURL, checksumURL, filename, err := resolve(m.baseURL(), image)
84		if err != nil {
85			return "", err
86		}
87		cachePath := filepath.Join(m.CacheDir, filename)
88		if _, err := os.Stat(cachePath); err == nil {
89			return cachePath, nil
90		}
91		if err := os.MkdirAll(m.CacheDir, 0o755); err != nil {
92			return "", fmt.Errorf("creating image cache dir: %w", err)
93		}
94	
95		tmp := cachePath + ".part"
96		sum, err := m.download(ctx, imageURL, tmp)
97		if err != nil {
98			os.Remove(tmp)
99			return "", err
100		}
101	
102		if expected, ok := m.fetchChecksum(ctx, checksumURL, filename); ok {
103			if !strings.EqualFold(expected, sum) {
104				os.Remove(tmp)
105				return "", fmt.Errorf("checksum mismatch for %s: expected %s, got %s", filename, expected, sum)
106			}
107		} else {
108			fmt.Fprintf(m.progress(), "warning: no checksum available for %s; skipping verification\n", filename)
109		}
110	
111		if err := os.Rename(tmp, cachePath); err != nil {
112			os.Remove(tmp)
113			return "", fmt.Errorf("finalizing cached image: %w", err)
114		}
115		return cachePath, nil
116	}
117	
118	// download streams imageURL to dst, reporting progress, and returns the SHA-256
119	// of the downloaded bytes.
120	func (m *Manager) download(ctx context.Context, imageURL, dst string) (string, error) {
121		req, err := http.NewRequestWithContext(ctx, http.MethodGet, imageURL, nil)
122		if err != nil {
123			return "", err
124		}
125		resp, err := m.client().Do(req)
126		if err != nil {
127			return "", fmt.Errorf("downloading %s: %w", imageURL, err)
128		}
129		defer resp.Body.Close()
130		if resp.StatusCode != http.StatusOK {
131			return "", fmt.Errorf("downloading %s: HTTP %d", imageURL, resp.StatusCode)
132		}
133	
134		f, err := os.Create(dst)
135		if err != nil {
136			return "", err
137		}
138		defer f.Close()
139	
140		hasher := sha256.New()
141		pr := &progressReader{r: resp.Body, total: resp.ContentLength, w: m.progress(), name: filepath.Base(imageURL)}
142		if _, err := io.Copy(io.MultiWriter(f, hasher), pr); err != nil {
143			return "", fmt.Errorf("writing image: %w", err)
144		}
145		pr.finish()
146		return hex.EncodeToString(hasher.Sum(nil)), nil
147	}
148	
149	// fetchChecksum returns the expected SHA-256 for filename from a SHA256SUMS
150	// document, or ok=false if it cannot be retrieved.
151	func (m *Manager) fetchChecksum(ctx context.Context, checksumURL, filename string) (string, bool) {
152		req, err := http.NewRequestWithContext(ctx, http.MethodGet, checksumURL, nil)
153		if err != nil {
154			return "", false
155		}
156		resp, err := m.client().Do(req)
157		if err != nil || resp.StatusCode != http.StatusOK {
158			if resp != nil {
159				resp.Body.Close()
160			}
161			return "", false
162		}
163		defer resp.Body.Close()
164		body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
165		if err != nil {
166			return "", false
167		}
168		return parseChecksum(string(body), filename)
169	}
170	
171	// parseChecksum extracts the hex digest for filename from SHA256SUMS content.
172	func parseChecksum(content, filename string) (string, bool) {
173		for _, line := range strings.Split(content, "\n") {
174			fields := strings.Fields(line)
175			if len(fields) != 2 {
176				continue
177			}
178			name := strings.TrimPrefix(fields[1], "*")
179			if name == filename {
180				return fields[0], true
181			}
182		}
183		return "", false
184	}
185	
186	func (m *Manager) client() *http.Client {
187		if m.Client != nil {
188			return m.Client
189		}
190		return http.DefaultClient
191	}
192	
193	func (m *Manager) baseURL() string {
194		if m.BaseURL != "" {
195			return m.BaseURL
196		}
197		return DefaultBaseURL
198	}
199	
200	func (m *Manager) progress() io.Writer {
201		if m.Progress != nil {
202			return m.Progress
203		}
204		return os.Stderr
205	}
206	
207	// progressReader reports download progress as bytes flow through it.
208	type progressReader struct {
209		r        io.Reader
210		total    int64
211		read     int64
212		w        io.Writer
213		name     string
214		lastPct  int
215		reported bool
216	}
217	
218	func (p *progressReader) Read(b []byte) (int, error) {
219		n, err := p.r.Read(b)
220		p.read += int64(n)
221		if p.total > 0 {
222			pct := int(p.read * 100 / p.total)
223			if pct != p.lastPct {
224				p.lastPct = pct
225				fmt.Fprintf(p.w, "\rdownloading %s: %d%%", p.name, pct)
226				p.reported = true
227			}
228		}
229		return n, err
230	}
231	
232	func (p *progressReader) finish() {
233		if p.reported {
234			fmt.Fprintf(p.w, "\rdownloading %s: done\n", p.name)
235		}
236	}
