294	// checkPrereqs verifies the local toolchain and /dev/kvm access.
295	func (p *Provider) checkPrereqs() error {
296		required := map[string]string{
297			"virsh":        "virsh not found: install libvirt (sudo apt install libvirt-daemon-system)",
298			"virt-install": "virt-install not found: install virtinst (sudo apt install virtinst)",
299			"qemu-img":     "qemu-img not found: install qemu-utils (sudo apt install qemu-utils)",
300		}
301		for bin, msg := range required {
302			if _, err := exec.LookPath(bin); err != nil {
303				return fmt.Errorf("%s", msg)
304			}
305		}
306		if detectISOTool() == isoNone {
307			return fmt.Errorf("neither cloud-localds nor genisoimage found: install cloud-image-utils or genisoimage")
308		}
309		if _, err := os.Stat("/dev/kvm"); err != nil {
310			return fmt.Errorf("/dev/kvm not accessible: check that the current user is in the 'kvm' group")
311		}
312		return nil
313	}
314	
315	// detectISOTool returns the preferred available NoCloud ISO generator.
316	func detectISOTool() isoTool {
317		if _, err := exec.LookPath("cloud-localds"); err == nil {
318			return isoCloudLocalds
319		}
320		if _, err := exec.LookPath("genisoimage"); err == nil {
321			return isoGenisoimage
322		}
323		return isoNone
324	}
