326	// parseMemoryMB converts a memory string ("2G", "512M", "1024") to megabytes.
327	func parseMemoryMB(mem string) (int, error) {
328		s := strings.TrimSpace(mem)
329		if s == "" {
330			return 0, fmt.Errorf("empty memory value")
331		}
332		mult := 1
333		switch last := s[len(s)-1]; last {
334		case 'G', 'g':
335			mult = 1024
336			s = s[:len(s)-1]
337		case 'M', 'm':
338			mult = 1
339			s = s[:len(s)-1]
340		}
341		n, err := strconv.Atoi(strings.TrimSpace(s))
342		if err != nil {
343			return 0, fmt.Errorf("invalid memory value %q: %w", mem, err)
344		}
345		return n * mult, nil
346	}
