348	// mapOSVariant maps an image shorthand to a libvirt os-variant, falling back to
349	// ubuntu20.04 for unknown values.
350	func mapOSVariant(image string) string {
351		switch image {
352		case "24.04":
353			return "ubuntu24.04"
354		case "22.04":
355			return "ubuntu22.04"
356		case "20.04":
357			return "ubuntu20.04"
358		default:
359			return "ubuntu20.04"
360		}
361	}
