9	// dnsmasqLeasesPath is the libvirt dnsmasq lease file for a given network.
10	func dnsmasqLeasesPath(network string) string {
11		return "/var/lib/libvirt/dnsmasq/" + network + ".leases"
12	}
13	
14	// lookupIP performs a single IP lookup for a VM: first via the DHCP lease
15	// source, then by matching the domain MAC against the dnsmasq lease file.
16	// Returns "" when no address is known yet.
17	func lookupIP(ctx context.Context, r Runner, name, network string) string {
18		if out, err := r.Output(ctx, "virsh", "domifaddr", name, "--source", "lease"); err == nil {
19			if ip := parseDomifaddr(string(out)); ip != "" {
20				return ip
21			}
22		}
23		// Fallback: resolve the interface MAC, then scan the dnsmasq lease file.
24		out, err := r.Output(ctx, "virsh", "domiflist", name)
25		if err != nil {
26			return ""
27		}
28		mac := parseDomiflistMAC(string(out))
29		if mac == "" {
30			return ""
31		}
32		content, err := os.ReadFile(dnsmasqLeasesPath(network))
33		if err != nil {
34			return ""
35		}
36		return parseDnsmasqLease(string(content), mac)
37	}
38	
39	// pollConfig controls IP/SSH polling cadence. Exposed for tests.
40	type pollConfig struct {
41		interval time.Duration
42		timeout  time.Duration
43	}
44	
45	var defaultIPPoll = pollConfig{interval: 2 * time.Second, timeout: 60 * time.Second}
46	
47	// pollIP repeatedly calls lookupIP until an address is found or the timeout
48	// elapses. Returns "" on timeout.
49	func pollIP(ctx context.Context, r Runner, name, network string, pc pollConfig) string {
50		deadline := time.Now().Add(pc.timeout)
51		for {
52			if ip := lookupIP(ctx, r, name, network); ip != "" {
53				return ip
54			}
55			if time.Now().After(deadline) {
56				return ""
57			}
58			select {
59			case <-ctx.Done():
60				return ""
61			case <-time.After(pc.interval):
62			}
63		}
64	}
