11	const hostsFile = "/etc/hosts"
12	
13	// hostsBlock renders the marker-delimited /etc/hosts entry for a VM. fqdn may be
14	// empty, in which case only the VM name is listed.
15	func hostsBlock(name, ip, fqdn string) string {
16		line := fmt.Sprintf("%s\t%s", ip, name)
17		if fqdn != "" {
18			line += " " + fqdn
19		}
20		return fmt.Sprintf("# govirt:%s\n%s\n# /govirt:%s\n", name, line, name)
21	}
22	
23	// removeHostsBlock returns existing with any govirt block for name removed.
24	func removeHostsBlock(existing, name string) string {
25		start := "# govirt:" + name
26		end := "# /govirt:" + name
27		lines := strings.Split(existing, "\n")
28		var out []string
29		skipping := false
30		for _, line := range lines {
31			trimmed := strings.TrimSpace(line)
32			if trimmed == start {
33				skipping = true
34				continue
35			}
36			if skipping {
37				if trimmed == end {
38					skipping = false
39				}
40				continue
41			}
42			out = append(out, line)
43		}
44		return strings.Join(out, "\n")
45	}
46	
47	// upsertHostsBlock removes any existing block for name and appends the new one.
48	func upsertHostsBlock(existing, name, block string) string {
49		cleaned := strings.TrimRight(removeHostsBlock(existing, name), "\n")
50		if cleaned == "" {
51			return block
52		}
53		return cleaned + "\n" + block
54	}
55	
56	// writeHostsFile writes content to /etc/hosts via `sudo tee`, piping content on
57	// stdin so nothing is interpolated into a shell command.
58	func writeHostsFile(content string) error {
59		cmd := exec.Command("sudo", "tee", hostsFile)
60		cmd.Stdin = bytes.NewReader([]byte(content))
61		cmd.Stdout = nil
62		var stderr bytes.Buffer
63		cmd.Stderr = &stderr
64		if err := cmd.Run(); err != nil {
65			return fmt.Errorf("updating %s: %s: %w", hostsFile, strings.TrimSpace(stderr.String()), err)
66		}
67		return nil
68	}
69	
70	// addHostsEntry adds or replaces the /etc/hosts entry for a VM. A failure is
71	// reported to the caller but is non-fatal at the call site.
72	func addHostsEntry(name, ip, fqdn string) error {
73		existing, err := os.ReadFile(hostsFile)
74		if err != nil {
75			return fmt.Errorf("reading %s: %w", hostsFile, err)
76		}
77		updated := upsertHostsBlock(string(existing), name, hostsBlock(name, ip, fqdn))
78		if !strings.HasSuffix(updated, "\n") {
79			updated += "\n"
80		}
81		return writeHostsFile(updated)
82	}
83	
84	// removeHostsEntry removes the /etc/hosts entry for a VM.
85	func removeHostsEntry(name string) error {
86		existing, err := os.ReadFile(hostsFile)
87		if err != nil {
88			return fmt.Errorf("reading %s: %w", hostsFile, err)
89		}
90		updated := strings.TrimRight(removeHostsBlock(string(existing), name), "\n") + "\n"
91		return writeHostsFile(updated)
92	}
