29	// New returns a Provider that builds clients from the default AWS credential
30	// chain.
31	func New() *Provider {
32		return &Provider{
33			newClients: loadClients,
34			StackPoll:  defaultStackPoll,
35			Out:        os.Stderr,
36		}
