127	// Delete tears down DNS records, the CloudFormation stack, and any network
128	// resources govirt created, then clears cfg.AWS.
129	func (p *Provider) Delete(ctx context.Context, cfg *config.Config) error {
130		if cfg.AWS == nil {
131			return fmt.Errorf("VM not found: check 'govirt list' for available VMs")
132		}
133		if err := config.ValidateName(cfg.VM.Name); err != nil {
134			return err
135		}
136		cl, err := p.clients(ctx, cfg.VM.Region)
137		if err != nil {
138			return err
139		}
140	
141		if err := deleteDNS(ctx, cl.route53, cfg); err != nil {
142			fmt.Fprintf(p.out(), "warning: deleting DNS records: %v\n", err)
143		}
144		if cfg.AWS.StackName != "" {
145			if err := deleteStack(ctx, cl.cfn, cfg.AWS.StackName); err != nil {
146				return err
147			}
148		}
149		if err := cleanupNetwork(ctx, cl.ec2, cfg.AWS); err != nil {
150			fmt.Fprintf(p.out(), "warning: cleaning up network resources: %v\n", err)
151		}
152		cfg.AWS = nil
153		return nil
154	}
