179	// List returns all EC2 instances visible to the credentials, excluding
180	// terminated ones. govirt does not own a global registry of instances, so this
181	// reflects the account's running fleet in the configured region.
182	func (p *Provider) List(ctx context.Context) ([]provider.VMStatus, error) {
183		cl, err := p.clients(ctx, config.DefaultRegion)
184		if err != nil {
185			return nil, err
186		}
187		out, err := cl.ec2.DescribeInstances(ctx, &ec2.DescribeInstancesInput{})
188		if err != nil {
189			return nil, fmt.Errorf("listing instances: %w", err)
190		}
191		var result []provider.VMStatus
192		for _, r := range out.Reservations {
193			for i := range r.Instances {
194				inst := &r.Instances[i]
195				name := instanceName(inst)
196				state, ip, created := instanceStatus(inst)
197				if state == "terminated" {
198					continue
199				}
200				result = append(result, provider.VMStatus{
201					Name:      name,
202					State:     state,
203					IP:        ip,
204					Provider:  p.Name(),
205					CreatedAt: created,
206				})
207			}
208		}
209		return result, nil
210	}
