10	)
11	
12	// createDNS resolves the hosted zone (when not pinned in config), creates all
13	// planned records pointing at publicIP, and records them in AWS state for later
14	// deletion. It is a no-op when no dns section is present.
15	func createDNS(ctx context.Context, api route53API, cfg *config.Config, publicIP string) error {
16		if cfg.DNS == nil || cfg.DNS.Domain == "" {
17			return nil
18		}
19		zoneID := cfg.DNS.ZoneID
20		if zoneID == "" {
21			id, err := lookupZoneID(ctx, api, cfg.DNS.Domain)
22			if err != nil {
23				return err
24			}
25			zoneID = id
26		}
27	
28		specs := planRecords(cfg.DNS, publicIP)
29		for _, spec := range specs {
30			if err := changeRecord(ctx, api, zoneID, r53types.ChangeActionUpsert, spec); err != nil {
31				return err
32			}
33			cfg.AWS.DNSRecords = append(cfg.AWS.DNSRecords, config.DNSRecord{Name: spec.Name, Type: spec.Type})
34		}
35		cfg.AWS.ZoneID = zoneID
36		cfg.AWS.FQDN = fqdn(cfg.DNS.Hostname, cfg.DNS.Domain)
37		return nil
38	}
39	
40	// deleteDNS deletes every tracked record. Route53 DELETE requires the record's
41	// full definition, which is re-derived from the current dns config and the
42	// stored public IP. The first error is returned but all records are attempted.
43	func deleteDNS(ctx context.Context, api route53API, cfg *config.Config) error {
44		if cfg.AWS == nil || len(cfg.AWS.DNSRecords) == 0 || cfg.DNS == nil {
45			return nil
46		}
47		zoneID := cfg.AWS.ZoneID
48		if zoneID == "" {
49			zoneID = cfg.DNS.ZoneID
50		}
51		if zoneID == "" {
52			return fmt.Errorf("cannot delete DNS records: no zone ID in state")
53		}
54	
55		specByName := make(map[string]recordSpec)
56		for _, spec := range planRecords(cfg.DNS, cfg.AWS.PublicIP) {
57			specByName[spec.Name+"|"+spec.Type] = spec
58		}
59	
60		var firstErr error
61		for _, rec := range cfg.AWS.DNSRecords {
62			spec, ok := specByName[rec.Name+"|"+rec.Type]
63			if !ok {
64				spec = recordSpec{Name: rec.Name, Type: rec.Type, Value: cfg.AWS.PublicIP, TTL: int64(cfg.DNS.TTL)}
65			}
66			if err := changeRecord(ctx, api, zoneID, r53types.ChangeActionDelete, spec); err != nil && firstErr == nil {
67				firstErr = err
68			}
69		}
70		cfg.AWS.DNSRecords = nil
71		return firstErr
72	}
73	
74	// swapDNS upserts every planned record to point at the current public IP,
75	// re-creating CNAME aliases. It auto-resolves the zone if absent and refreshes
76	// the tracked record list and FQDN in state.
77	func swapDNS(ctx context.Context, api route53API, cfg *config.Config) error {
78		if cfg.DNS == nil || cfg.DNS.Domain == "" {
79			return fmt.Errorf("dns swap requires a dns section with a domain")
80		}
81		if cfg.AWS == nil || cfg.AWS.PublicIP == "" {
82			return fmt.Errorf("dns swap requires a current public IP in aws state")
83		}
84		zoneID := cfg.AWS.ZoneID
85		if zoneID == "" {
86			zoneID = cfg.DNS.ZoneID
87		}
88		if zoneID == "" {
89			id, err := lookupZoneID(ctx, api, cfg.DNS.Domain)
90			if err != nil {
91				return err
92			}
93			zoneID = id
94		}
95	
96		specs := planRecords(cfg.DNS, cfg.AWS.PublicIP)
97		var records []config.DNSRecord
98		for _, spec := range specs {
99			if err := changeRecord(ctx, api, zoneID, r53types.ChangeActionUpsert, spec); err != nil {
100				return err
101			}
102			records = append(records, config.DNSRecord{Name: spec.Name, Type: spec.Type})
103		}
104		cfg.AWS.ZoneID = zoneID
105		cfg.AWS.FQDN = fqdn(cfg.DNS.Hostname, cfg.DNS.Domain)
106		cfg.AWS.DNSRecords = records
107		return nil
108	}
