1	package aws
2	
3	import (
4		"context"
5		"fmt"
6		"strings"
7	
8		awssdk "github.com/aws/aws-sdk-go-v2/aws"
9		"github.com/aws/aws-sdk-go-v2/service/route53"
10		r53types "github.com/aws/aws-sdk-go-v2/service/route53/types"
11	
12		"github.com/gherlein/govirt/internal/config"
13	)
14	
15	// recordSpec describes a single DNS record govirt manages.
16	type recordSpec struct {
17		Name  string
18		Type  string
19		Value string
20		TTL   int64
21	}
22	
23	// planRecords builds the set of Route53 records to create for a deployment: the
24	// hostname A record, an apex A record when requested, and a CNAME per alias
25	// pointing at the hostname FQDN. publicIP is the A-record target.
26	func planRecords(dns *config.DNSConfig, publicIP string) []recordSpec {
27		domain := strings.TrimSuffix(dns.Domain, ".")
28		hostFQDN := fqdn(dns.Hostname, domain)
29		ttl := int64(dns.TTL)
30		if ttl == 0 {
31			ttl = config.DefaultTTL
32		}
33	
34		specs := []recordSpec{
35			{Name: hostFQDN, Type: "A", Value: publicIP, TTL: ttl},
36		}
37		if dns.IsApexDomain {
38			specs = append(specs, recordSpec{Name: domain + ".", Type: "A", Value: publicIP, TTL: ttl})
39		}
40		for _, alias := range dns.CNAMEAliases {
41			specs = append(specs, recordSpec{
42				Name:  fqdn(alias, domain),
43				Type:  "CNAME",
44				Value: hostFQDN,
45				TTL:   ttl,
46			})
47		}
48		return specs
49	}
50	
51	// fqdn joins a hostname and domain into a trailing-dot FQDN. An apex hostname
52	// (equal to the domain or empty) yields the bare domain.
53	func fqdn(host, domain string) string {
54		host = strings.TrimSuffix(host, ".")
55		if host == "" || host == domain {
56			return domain + "."
57		}
58		return host + "." + domain + "."
59	}
60	
61	// lookupZoneID resolves the hosted zone ID for a domain via
62	// ListHostedZonesByName, choosing an exact name match. The returned ID has the
63	// "/hostedzone/" prefix stripped.
64	func lookupZoneID(ctx context.Context, api route53API, domain string) (string, error) {
65		name := strings.TrimSuffix(domain, ".") + "."
66		out, err := api.ListHostedZonesByName(ctx, &route53.ListHostedZonesByNameInput{
67			DNSName: awssdk.String(name),
68		})
69		if err != nil {
70			return "", fmt.Errorf("looking up hosted zone for %s: %w", domain, err)
71		}
72		for _, z := range out.HostedZones {
73			if awssdk.ToString(z.Name) == name {
74				return strings.TrimPrefix(awssdk.ToString(z.Id), "/hostedzone/"), nil
75			}
76		}
77		return "", fmt.Errorf("no Route53 hosted zone found for domain %s", domain)
78	}
79	
80	// changeRecord submits a single record change (action is CREATE, DELETE, or
81	// UPSERT) to a hosted zone.
82	func changeRecord(ctx context.Context, api route53API, zoneID string, action r53types.ChangeAction, spec recordSpec) error {
83		_, err := api.ChangeResourceRecordSets(ctx, &route53.ChangeResourceRecordSetsInput{
84			HostedZoneId: awssdk.String(zoneID),
85			ChangeBatch: &r53types.ChangeBatch{
86				Changes: []r53types.Change{
87					{
88						Action:            action,
89						ResourceRecordSet: resourceRecordSet(spec),
90					},
91				},
92			},
93		})
94		if err != nil {
95			return fmt.Errorf("%s record %s (%s): %w", strings.ToLower(string(action)), spec.Name, spec.Type, err)
96		}
97		return nil
98	}
99	
100	// resourceRecordSet converts a recordSpec to the SDK record-set type.
101	func resourceRecordSet(spec recordSpec) *r53types.ResourceRecordSet {
102		rrType := r53types.RRTypeA
103		if strings.EqualFold(spec.Type, "CNAME") {
104			rrType = r53types.RRTypeCname
105		}
106		return &r53types.ResourceRecordSet{
107			Name:            awssdk.String(spec.Name),
108			Type:            rrType,
109			TTL:             awssdk.Int64(spec.TTL),
110			ResourceRecords: []r53types.ResourceRecord{{Value: awssdk.String(spec.Value)}},
111		}
112	}
