1	package aws
2	
3	import (
4		"context"
5		"fmt"
6		"time"
7	
8		awssdk "github.com/aws/aws-sdk-go-v2/aws"
9		"github.com/aws/aws-sdk-go-v2/service/ec2"
10		ec2types "github.com/aws/aws-sdk-go-v2/service/ec2/types"
11	
12		"github.com/gherlein/govirt/internal/config"
13	)
14	
15	// newVpcCidr is the CIDR for a VPC govirt creates when no usable VPC exists.
16	const newVpcCidr = "10.0.0.0/16"
17	
18	// newSubnetCidr is the CIDR for a subnet govirt creates inside a new VPC.
19	const newSubnetCidr = "10.0.1.0/24"
20	
21	// network holds the discovered or created VPC/subnet plus any resources govirt
22	// created so they can be recorded in state and cleaned up on destroy.
23	type network struct {
24		VpcID                 string
25		SubnetID              string
26		CreatedVPC            bool
27		CreatedSubnet         bool
28		InternetGatewayID     string
29		RouteTableID          string
30		RouteTableAssociation string
31	}
32	
33	// ensureNetwork resolves the VPC and subnet to launch into. Explicit vm.vpc_id
34	// and vm.subnet_id short-circuit discovery. Otherwise it follows the documented
35	// order: default VPC, then any available VPC, then create a full VPC stack;
36	// within the chosen VPC it finds a public-auto-assign subnet or creates one.
37	func ensureNetwork(ctx context.Context, api ec2API, vm *config.VMConfig) (*network, error) {
38		if vm.VpcID != "" && vm.SubnetID != "" {
39			return &network{VpcID: vm.VpcID, SubnetID: vm.SubnetID}, nil
40		}
41	
42		vpcID := vm.VpcID
43		if vpcID == "" {
44			discovered, created, err := discoverOrCreateVPC(ctx, api)
45			if err != nil {
46				return nil, err
47			}
48			return finishNetwork(ctx, api, discovered, created)
49		}
50	
51		subnetID, err := findPublicSubnet(ctx, api, vpcID)
52		if err != nil {
53			return nil, err
54		}
55		if subnetID == "" {
56			net := &network{VpcID: vpcID}
57			if err := createSubnetWithRouting(ctx, api, net, false); err != nil {
58				return nil, err
59			}
60			return net, nil
61		}
62		return &network{VpcID: vpcID, SubnetID: subnetID}, nil
63	}
64	
65	// finishNetwork resolves a subnet inside an already-chosen VPC. For a VPC govirt
66	// just created, routing (IGW + route table) is provisioned alongside the subnet.
67	func finishNetwork(ctx context.Context, api ec2API, net *network, createdVPC bool) (*network, error) {
68		net.CreatedVPC = createdVPC
69		if !createdVPC {
70			subnetID, err := findPublicSubnet(ctx, api, net.VpcID)
71			if err != nil {
72				return nil, err
73			}
74			if subnetID != "" {
75				net.SubnetID = subnetID
76				return net, nil
77			}
78		}
79		if err := createSubnetWithRouting(ctx, api, net, createdVPC); err != nil {
80			return nil, err
81		}
82		return net, nil
83	}
84	
85	// discoverOrCreateVPC returns the default VPC, else any available VPC, else a
86	// freshly created VPC. The boolean reports whether the VPC was created.
87	func discoverOrCreateVPC(ctx context.Context, api ec2API) (*network, bool, error) {
88		defaultVpc, err := api.DescribeVpcs(ctx, &ec2.DescribeVpcsInput{
89			Filters: []ec2types.Filter{{Name: awssdk.String("is-default"), Values: []string{"true"}}},
90		})
91		if err != nil {
92			return nil, false, fmt.Errorf("describing default VPC: %w", err)
93		}
94		if id := firstAvailableVpc(defaultVpc.Vpcs); id != "" {
95			return &network{VpcID: id}, false, nil
96		}
97	
98		all, err := api.DescribeVpcs(ctx, &ec2.DescribeVpcsInput{})
99		if err != nil {
100			return nil, false, fmt.Errorf("describing VPCs: %w", err)
101		}
102		if id := firstAvailableVpc(all.Vpcs); id != "" {
103			return &network{VpcID: id}, false, nil
104		}
105	
106		net := &network{}
107		created, err := api.CreateVpc(ctx, &ec2.CreateVpcInput{CidrBlock: awssdk.String(newVpcCidr)})
108		if err != nil {
109			return nil, false, fmt.Errorf("creating VPC: %w", err)
110		}
111		net.VpcID = awssdk.ToString(created.Vpc.VpcId)
112		return net, true, nil
113	}
114	
115	// firstAvailableVpc returns the ID of the first VPC in the available state, or
116	// "" when none qualifies.
117	func firstAvailableVpc(vpcs []ec2types.Vpc) string {
118		for _, v := range vpcs {
119			if v.State == ec2types.VpcStateAvailable && v.VpcId != nil {
120				return *v.VpcId
121			}
122		}
123		return ""
124	}
125	
126	// findPublicSubnet returns the first subnet in the VPC that auto-assigns public
127	// IPs, or "" if none does.
128	func findPublicSubnet(ctx context.Context, api ec2API, vpcID string) (string, error) {
129		out, err := api.DescribeSubnets(ctx, &ec2.DescribeSubnetsInput{
130			Filters: []ec2types.Filter{{Name: awssdk.String("vpc-id"), Values: []string{vpcID}}},
131		})
132		if err != nil {
133			return "", fmt.Errorf("describing subnets for %s: %w", vpcID, err)
134		}
135		return firstPublicSubnet(out.Subnets), nil
136	}
137	
138	// firstPublicSubnet returns the ID of the first available subnet with public IP
139	// auto-assignment enabled.
140	func firstPublicSubnet(subnets []ec2types.Subnet) string {
141		for _, s := range subnets {
142			if s.SubnetId == nil {
143				continue
144			}
145			if awssdk.ToBool(s.MapPublicIpOnLaunch) && s.State == ec2types.SubnetStateAvailable {
146				return *s.SubnetId
147			}
148		}
149		return ""
150	}
151	
152	// createSubnetWithRouting creates a public subnet in net.VpcID. When the VPC was
153	// just created by govirt, it also creates and attaches an Internet Gateway and a
154	// route table with a default route so the subnet is genuinely internet-facing.
155	// All created resources are recorded on net for cleanup.
156	func createSubnetWithRouting(ctx context.Context, api ec2API, net *network, createdVPC bool) error {
157		subnet, err := api.CreateSubnet(ctx, &ec2.CreateSubnetInput{
158			VpcId:     awssdk.String(net.VpcID),
159			CidrBlock: awssdk.String(newSubnetCidr),
160		})
161		if err != nil {
162			return fmt.Errorf("creating subnet: %w", err)
163		}
164		net.SubnetID = awssdk.ToString(subnet.Subnet.SubnetId)
165		net.CreatedSubnet = true
166	
167		if _, err := api.ModifySubnetAttribute(ctx, &ec2.ModifySubnetAttributeInput{
168			SubnetId:            awssdk.String(net.SubnetID),
169			MapPublicIpOnLaunch: &ec2types.AttributeBooleanValue{Value: awssdk.Bool(true)},
170		}); err != nil {
171			return fmt.Errorf("enabling public IP auto-assign on subnet: %w", err)
172		}
173	
174		if !createdVPC {
175			return nil
176		}
177	
178		igw, err := api.CreateInternetGateway(ctx, &ec2.CreateInternetGatewayInput{})
179		if err != nil {
180			return fmt.Errorf("creating internet gateway: %w", err)
181		}
182		net.InternetGatewayID = awssdk.ToString(igw.InternetGateway.InternetGatewayId)
183		if _, err := api.AttachInternetGateway(ctx, &ec2.AttachInternetGatewayInput{
184			InternetGatewayId: awssdk.String(net.InternetGatewayID),
185			VpcId:             awssdk.String(net.VpcID),
186		}); err != nil {
187			return fmt.Errorf("attaching internet gateway: %w", err)
188		}
189	
190		rt, err := api.CreateRouteTable(ctx, &ec2.CreateRouteTableInput{VpcId: awssdk.String(net.VpcID)})
191		if err != nil {
192			return fmt.Errorf("creating route table: %w", err)
193		}
194		net.RouteTableID = awssdk.ToString(rt.RouteTable.RouteTableId)
195		if _, err := api.CreateRoute(ctx, &ec2.CreateRouteInput{
196			RouteTableId:         awssdk.String(net.RouteTableID),
197			DestinationCidrBlock: awssdk.String("0.0.0.0/0"),
198			GatewayId:            awssdk.String(net.InternetGatewayID),
199		}); err != nil {
200			return fmt.Errorf("creating default route: %w", err)
201		}
202		assoc, err := api.AssociateRouteTable(ctx, &ec2.AssociateRouteTableInput{
203			RouteTableId: awssdk.String(net.RouteTableID),
204			SubnetId:     awssdk.String(net.SubnetID),
205		})
206		if err != nil {
207			return fmt.Errorf("associating route table: %w", err)
208		}
209		net.RouteTableAssociation = awssdk.ToString(assoc.AssociationId)
210		return nil
211	}
212	
213	// applyNetworkState records discovered/created network resources into AWS state.
214	func applyNetworkState(state *config.AWSState, net *network) {
215		state.VpcID = net.VpcID
216		state.SubnetID = net.SubnetID
217		state.CreatedVPC = net.CreatedVPC
218		state.CreatedSubnet = net.CreatedSubnet
219		state.InternetGatewayID = net.InternetGatewayID
220		state.RouteTableID = net.RouteTableID
221		state.RouteTableAssociation = net.RouteTableAssociation
222	}
223	
224	// cleanupNetwork deletes only the network resources govirt created, in reverse
225	// dependency order. Errors are returned for the caller to surface but each step
226	// is attempted regardless of earlier failures so partial cleanup can proceed.
227	func cleanupNetwork(ctx context.Context, api ec2API, state *config.AWSState) error {
228		var firstErr error
229		record := func(err error) {
230			if err != nil && firstErr == nil {
231				firstErr = err
232			}
233		}
234	
235		if state.RouteTableAssociation != "" {
236			_, err := api.DisassociateRouteTable(ctx, &ec2.DisassociateRouteTableInput{
237				AssociationId: awssdk.String(state.RouteTableAssociation),
238			})
239			record(err)
240		}
241		if state.RouteTableID != "" {
242			_, err := api.DeleteRouteTable(ctx, &ec2.DeleteRouteTableInput{
243				RouteTableId: awssdk.String(state.RouteTableID),
244			})
245			record(err)
246		}
247		if state.InternetGatewayID != "" && state.VpcID != "" {
248			_, err := api.DetachInternetGateway(ctx, &ec2.DetachInternetGatewayInput{
249				InternetGatewayId: awssdk.String(state.InternetGatewayID),
250				VpcId:             awssdk.String(state.VpcID),
251			})
252			record(err)
253			_, err = api.DeleteInternetGateway(ctx, &ec2.DeleteInternetGatewayInput{
254				InternetGatewayId: awssdk.String(state.InternetGatewayID),
255			})
256			record(err)
257		}
258		if state.CreatedSubnet && state.SubnetID != "" {
259			_, err := api.DeleteSubnet(ctx, &ec2.DeleteSubnetInput{SubnetId: awssdk.String(state.SubnetID)})
260			record(err)
261		}
262		if state.CreatedVPC && state.VpcID != "" {
263			_, err := api.DeleteVpc(ctx, &ec2.DeleteVpcInput{VpcId: awssdk.String(state.VpcID)})
264			record(err)
265		}
266		return firstErr
267	}
268	
269	// describeInstance returns the EC2 instance matching id, or an error if it is
270	// absent.
271	func describeInstance(ctx context.Context, api ec2API, id string) (*ec2types.Instance, error) {
272		out, err := api.DescribeInstances(ctx, &ec2.DescribeInstancesInput{InstanceIds: []string{id}})
273		if err != nil {
274			return nil, fmt.Errorf("describing instance %s: %w", id, err)
275		}
276		for _, r := range out.Reservations {
277			for i := range r.Instances {
278				return &r.Instances[i], nil
279			}
280		}
281		return nil, fmt.Errorf("instance %s not found", id)
282	}
283	
284	// instanceStatus normalizes an EC2 instance into state, public IP, and launch
285	// time.
286	func instanceStatus(inst *ec2types.Instance) (state, ip string, created time.Time) {
287		if inst.State != nil {
288			state = string(inst.State.Name)
289		}
290		ip = awssdk.ToString(inst.PublicIpAddress)
291		if inst.LaunchTime != nil {
292			created = *inst.LaunchTime
293		}
294		return state, ip, created
295	}
