6	
7		"github.com/digitalocean/godo"
8		"github.com/gherlein/govirt/internal/config"
9	)
10	
11	// buildARecord builds a request for an A record named name pointing at ip.
12	func buildARecord(name, ip string, ttl int) *godo.DomainRecordEditRequest {
13		return &godo.DomainRecordEditRequest{
14			Type: "A",
15			Name: name,
16			Data: ip,
17			TTL:  ttl,
18		}
19	}
20	
21	// buildCNAMERecord builds a request for a CNAME record named alias pointing at
22	// target. DigitalOcean requires CNAME data to be a fully qualified name ending
23	// in a dot.
24	func buildCNAMERecord(alias, target string, ttl int) *godo.DomainRecordEditRequest {
25		if len(target) == 0 || target[len(target)-1] != '.' {
26			target += "."
27		}
28		return &godo.DomainRecordEditRequest{
29			Type: "CNAME",
30			Name: alias,
31			Data: target,
32			TTL:  ttl,
33		}
34	}
35	
36	// planDNSRecords returns the ordered set of record-edit requests to create for
37	// the given config and droplet IP: the hostname A record, an optional apex A
38	// record, and one CNAME per alias pointing at the hostname FQDN. The DNS section
39	// being nil yields no records.
40	func planDNSRecords(cfg *config.Config, ip string) []*godo.DomainRecordEditRequest {
41		if cfg.DNS == nil {
42			return nil
43		}
44		dns := cfg.DNS
45		ttl := dns.TTL
46		hostnameFQDN := dns.Hostname + "." + dns.Domain
47		var records []*godo.DomainRecordEditRequest
48		records = append(records, buildARecord(dns.Hostname, ip, ttl))
49		if dns.IsApexDomain {
50			records = append(records, buildARecord("@", ip, ttl))
51		}
52		for _, alias := range dns.CNAMEAliases {
53			records = append(records, buildCNAMERecord(alias, hostnameFQDN, ttl))
54		}
55		return records
56	}
57	
58	// createDNSRecords creates all planned DNS records in cfg.DNS.Domain and returns
59	// the tracked DORecords (with their DigitalOcean numeric IDs).
60	func (p *Provider) createDNSRecords(ctx context.Context, cfg *config.Config, ip string) ([]config.DORecord, error) {
61		plan := planDNSRecords(cfg, ip)
62		if len(plan) == 0 {
63			return nil, nil
64		}
65		domain := cfg.DNS.Domain
66		var tracked []config.DORecord
67		for _, req := range plan {
68			rec, _, err := p.api.Domains().CreateRecord(ctx, domain, req)
69			if err != nil {
70				return tracked, fmt.Errorf("creating %s record %q: %w", req.Type, req.Name, err)
71			}
72			tracked = append(tracked, config.DORecord{ID: rec.ID, Name: req.Name, Type: req.Type})
73		}
74		return tracked, nil
75	}
76	
77	// deleteDNSRecords deletes every tracked DNS record. It continues past
78	// individual failures and returns the first error encountered.
79	func (p *Provider) deleteDNSRecords(ctx context.Context, cfg *config.Config) error {
80		if cfg.DO == nil || cfg.DNS == nil {
81			return nil
82		}
83		domain := cfg.DNS.Domain
84		var firstErr error
85		for _, rec := range cfg.DO.DNSRecords {
86			if _, err := p.api.Domains().DeleteRecord(ctx, domain, rec.ID); err != nil && firstErr == nil {
87				firstErr = fmt.Errorf("deleting %s record %q: %w", rec.Type, rec.Name, err)
88			}
89		}
90		cfg.DO.DNSRecords = nil
91		return firstErr
92	}
93	
94	// SwapDNS updates every tracked A record to the droplet's current public IP and
95	// re-creates the configured CNAME aliases. It implements provider.DNSSwapper.
96	func (p *Provider) SwapDNS(ctx context.Context, cfg *config.Config) error {
97		if cfg.DO == nil {
98			return fmt.Errorf("no DigitalOcean state for %s: nothing to swap", cfg.VM.Name)
99		}
100		if cfg.DNS == nil {
101			return fmt.Errorf("no dns section for %s: nothing to swap", cfg.VM.Name)
102		}
103		droplet, _, err := p.api.Droplets().Get(ctx, cfg.DO.DropletID)
104		if err != nil {
105			return fmt.Errorf("getting droplet %d: %w", cfg.DO.DropletID, err)
106		}
107		ip, err := droplet.PublicIPv4()
108		if err != nil || ip == "" {
109			return fmt.Errorf("droplet %d has no public IP", cfg.DO.DropletID)
110		}
111	
112		domain := cfg.DNS.Domain
113		ttl := cfg.DNS.TTL
114		hostnameFQDN := cfg.DNS.Hostname + "." + cfg.DNS.Domain
115	
116		var updated []config.DORecord
117		for _, rec := range cfg.DO.DNSRecords {
118			switch rec.Type {
119			case "A":
120				req := buildARecord(rec.Name, ip, ttl)
121				if _, _, err := p.api.Domains().EditRecord(ctx, domain, rec.ID, req); err != nil {
122					return fmt.Errorf("updating A record %q: %w", rec.Name, err)
123				}
124				updated = append(updated, rec)
125			case "CNAME":
126				// Re-create CNAME aliases so they re-point at the current hostname FQDN.
127				if _, err := p.api.Domains().DeleteRecord(ctx, domain, rec.ID); err != nil {
128					return fmt.Errorf("removing stale CNAME %q: %w", rec.Name, err)
129				}
130				req := buildCNAMERecord(rec.Name, hostnameFQDN, ttl)
131				newRec, _, err := p.api.Domains().CreateRecord(ctx, domain, req)
132				if err != nil {
133					return fmt.Errorf("re-creating CNAME %q: %w", rec.Name, err)
134				}
135				updated = append(updated, config.DORecord{ID: newRec.ID, Name: rec.Name, Type: "CNAME"})
136			default:
137				updated = append(updated, rec)
138			}
139		}
140		cfg.DO.DNSRecords = updated
141		cfg.DO.PublicIP = ip
142		return nil
143	}
