1	package digitalocean
2	
3	import (
4		"context"
5		"fmt"
6	
7		"github.com/digitalocean/godo"
8		"github.com/gherlein/govirt/internal/config"
9	)
10	
11	// DefaultCIDR is the firewall source used when ssh_cidr/web_cidr are unset.
12	const DefaultCIDR = "0.0.0.0/0"
13	
14	// buildFirewallRequest builds a firewall allowing inbound TCP on 22 (SSH), 80
15	// and 443 (web), attached to the given droplet. SSH uses ssh_cidr; HTTP/HTTPS
16	// use web_cidr; both default to 0.0.0.0/0 when unset.
17	func buildFirewallRequest(cfg *config.Config, dropletID int) *godo.FirewallRequest {
18		sshCIDR := cfg.VM.SSHCidr
19		if sshCIDR == "" {
20			sshCIDR = DefaultCIDR
21		}
22		webCIDR := cfg.VM.WebCidr
23		if webCIDR == "" {
24			webCIDR = DefaultCIDR
25		}
26		inbound := func(port, cidr string) godo.InboundRule {
27			return godo.InboundRule{
28				Protocol:  "tcp",
29				PortRange: port,
30				Sources:   &godo.Sources{Addresses: []string{cidr}},
31			}
32		}
33		return &godo.FirewallRequest{
34			Name: "govirt-" + cfg.VM.Name,
35			InboundRules: []godo.InboundRule{
36				inbound("22", sshCIDR),
37				inbound("80", webCIDR),
38				inbound("443", webCIDR),
39			},
40			DropletIDs: []int{dropletID},
41		}
42	}
43	
44	// createFirewall creates and attaches the firewall, returning its id.
45	func (p *Provider) createFirewall(ctx context.Context, cfg *config.Config, dropletID int) (string, error) {
46		req := buildFirewallRequest(cfg, dropletID)
47		fw, _, err := p.api.Firewalls().Create(ctx, req)
48		if err != nil {
49			return "", fmt.Errorf("creating firewall: %w", err)
50		}
51		return fw.ID, nil
52	}
